class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __sub__(self, other):
        return Vector(self.x - other.x, self.y - other.y)

    def __mul__(self, scalar):
        return Vector(self.x * scalar, self.y * scalar)

    def __eq__(self, other):
        return self.x == other.x and self.y == other.y

    def __str__(self):
        return f"Vector({self.x}, {self.y})"

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    def __len__(self):
        return int((self.x ** 2 + self.y ** 2) ** 0.5)

    def __getitem__(self, index):
        return [self.x, self.y][index]

    def __call__(self, factor):
        return Vector(self.x * factor, self.y * factor)

v1 = Vector(2, 3)
v2 = Vector(4, 5)
v3 = v1 + v2
print(v3)  # Vector(6, 8)
print(len(v1))  # 3
print(v1[0])  # 2
print(v1(2))  # Vector(4, 6)

class SingletonMeta(type):
    """Metaclass implementing Singleton pattern"""
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class DatabaseConnection(metaclass=SingletonMeta):
    def __init__(self):
        print("Creating database connection")
        self.connected = True

    def query(self, sql):
        return f"Executing: {sql}"

db1 = DatabaseConnection()  # Creating database connection
db2 = DatabaseConnection()  # No output - reuses instance
print(db1 is db2)  # True

# Metaclass for automatic class registration
class PluginRegistry(type):
    registry = {}

    def __new__(cls, name, bases, attrs):
        new_class = super().__new__(cls, name, bases, attrs)
        if name != 'Plugin':
            cls.registry[name] = new_class
        return new_class

class Plugin(metaclass=PluginRegistry):
    pass

class AudioPlugin(Plugin):
    def process(self):
        return "Processing audio"

class VideoPlugin(Plugin):
    def process(self):
        return "Processing video"

print(PluginRegistry.registry)  # {'AudioPlugin': ..., 'VideoPlugin': ...}

class A:
    def __init__(self):
        print("A init")

    def method(self):
        return "A.method"

class B(A):
    def __init__(self):
        print("B init")
        super().__init__()

    def method(self):
        return f"B.method -> {super().method()}"

class C(A):
    def __init__(self):
        print("C init")
        super().__init__()

    def method(self):
        return f"C.method -> {super().method()}"

class D(B, C):
    def __init__(self):
        print("D init")
        super().__init__()

    def method(self):
        return f"D.method -> {super().method()}"

# Method Resolution Order
print(D.__mro__)  # (<class 'D'>, <class 'B'>, <class 'C'>, <class 'A'>, <class 'object'>)

d = D()
# D init
# B init
# C init
# A init

print(d.method())  # D.method -> B.method -> C.method -> A.method

# Mixin classes
class LoggingMixin:
    def log(self, message):
        print(f"[LOG] {message}")

class TimingMixin:
    import time
    def timed(self, func):
        start = time.time()
        result = func()
        end = time.time()
        print(f"Time: {end - start}s")
        return result

class Service(LoggingMixin, TimingMixin):
    def process(self):
        self.log("Processing started")
        return "Processed"

s = Service()
s.process()

from abc import ABC, abstractmethod

class Shape(ABC):
    @abstractmethod
    def area(self):
        pass

    @abstractmethod
    def perimeter(self):
        pass

    def describe(self):
        return f"{self.__class__.__name__}: area={self.area()}, perimeter={self.perimeter()}"

class Rectangle(Shape):
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

    def perimeter(self):
        return 2 * (self.width + self.height)

class Circle(Shape):
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        import math
        return math.pi * self.radius ** 2

    def perimeter(self):
        import math
        return 2 * math.pi * self.radius

def print_shape_info(shape):
    """Polymorphic function works with any Shape subclass"""
    print(shape.describe())

shapes = [Rectangle(5, 3), Circle(4)]
for shape in shapes:
    print_shape_info(shape)

# Checking abstract method implementation
try:
    class Incomplete(Shape):
        def area(self):
            return 0
    incomplete = Incomplete()  # TypeError: Can't instantiate abstract class
except TypeError as e:
    print(f"Error: {e}")

# Method 1: Using __new__
class Singleton1:
    _instance = None

    def __new__(cls, *args, **kwargs):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance

    def __init__(self, value=None):
        if not hasattr(self, '_initialized'):
            self.value = value
            self._initialized = True

# Method 2: Using decorator
def singleton(cls):
    instances = {}

    def wrapper(*args, **kwargs):
        if cls not in instances:
            instances[cls] = cls(*args, **kwargs)
        return instances[cls]
    return wrapper

@singleton
class Singleton2:
    def __init__(self, value):
        self.value = value

# Method 3: Using metaclass (most flexible)
class SingletonMeta(type):
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class Config(metaclass=SingletonMeta):
    def __init__(self, settings=None):
        if not hasattr(self, '_initialized'):
            self.settings = settings or {}
            self._initialized = True

    def get(self, key, default=None):
        return self.settings.get(key, default)

# Test all implementations
config1 = Config({"db": "postgres"})
config2 = Config()
print(config1 is config2)  # True
print(config1.get("db"))  # postgres

