s3 = Singleton2(30)
s4 = Singleton2(40)
print(s3.value, s4.value)  # 30 30 (same instance)

# Class decorator for adding methods
def add_timing(cls):
    import time

    def timed_method(method):
        def wrapper(self, *args, **kwargs):
            start = time.time()
            result = method(self, *args, **kwargs)
            end = time.time()
            print(f"{method.__name__} took {end-start:.4f}s")
            return result
        return wrapper

    for attr_name, attr_value in cls.__dict__.items():
        if callable(attr_value) and not attr_name.startswith('_'):
            setattr(cls, attr_name, timed_method(attr_value))
    return cls

@add_timing
class Calculator:
    def expensive_computation(self):
        import time
        time.sleep(1)
        return 42

    def another_method(self):
        import time
        time.sleep(0.5)
        return "done"

calc = Calculator()
calc.expensive_computation()  # expensive_computation took 1.0002s
calc.another_method()  # another_method took 0.5001s

# Descriptor for type validation
class TypedAttribute:
    def __init__(self, name, expected_type):
        self.name = name
        self.expected_type = expected_type

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        return obj.__dict__.get(self.name)

    def __set__(self, obj, value):
        if not isinstance(value, self.expected_type):
            raise TypeError(f"Expected {self.expected_type.__name__}, got {type(value).__name__}")
        obj.__dict__[self.name] = value

class Person:
    name = TypedAttribute('name', str)
    age = TypedAttribute('age', int)

    def __init__(self, name, age):
        self.name = name
        self.age = age

p = Person("Alice", 30)
print(p.name, p.age)  # Alice 30
# p.age = "thirty"  # TypeError: Expected int, got str

# Property-like descriptor
class LazyProperty:
    def __init__(self, func):
        self.func = func
        self.name = func.__name__

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        value = self.func(obj)
        obj.__dict__[self.name] = value
        return value

class DataProcessor:
    def __init__(self, data):
        self.data = data

    @LazyProperty
    def processed(self):
        print("Processing...")
        return [x * 2 for x in self.data]

dp = DataProcessor([1, 2, 3])
print(dp.processed)  # Processing... [2, 4, 6]
print(dp.processed)  # [2, 4, 6] (cached)
